urlset:
{%- for file in pages -%}
    {% if not file.page.is_link and (file.page.abs_url or file.page.canonical_url) %}

         {% if file.page.canonical_url %}{{ file.page.canonical_url|e }}{% else %}{{ file.page.abs_url|e }}{% endif %}
         {%- set gitdate = file.page.meta.git_revision_date_localized_raw_iso_date
                           or file.page.meta.git_revision_date_localized
                           or file.page.update_date %}
         {%- if gitdate %}
         {{ gitdate }}
         {%- endif %}

    {%- endif -%}
{% endfor %}
